import {useMemo} from 'react';
import type {IStyleClasses} from '@lmb-it/kitsconcerto-types';

/**
 * Web stub for useFocusStyles.
 * On web, focus styles are handled via CSS :focus pseudo-classes,
 * so this hook returns an empty object.
 */
export function useFocusStyles(
    _themeStyle: IStyleClasses | undefined,
    _isFocused: boolean,
) {
    return useMemo(() => ({}), []);
}

export default useFocusStyles;
